Template.Iscript:
                        Long parentFlags = flistGetLong(IN,PIN_FLD_PARENT_FLAGS);
                        if (parentFlags == 0) {
                                flistSetEnum( OUT, PIN_FLD_RESULT, 1);
		   		flistSetStr(OUT, PIN_FLD_NAME, "ConsumerInvoice");
                        } else if(parentFlags > 0) {
                                flistSetEnum(OUT, PIN_FLD_RESULT, 1);
                                flistSetStr(OUT, PIN_FLD_NAME, "CorporateInvoice");
                        }

		   Decimal CREDIT_LIMIT_ALLOWED = 0;
		   Poid inPoid = flistGetPoid(IN,PIN_FLD_POID);
		   String dbID = poidGetDbStr( inPoid );

		   Flist search = flistCreate();
		   Poid p = poidCreate (dbID,"/search", 500);
		   flistSetPoid( search, PIN_FLD_POID, p );
		   flistSetStr(search, PIN_FLD_PARAMETERS, "credit_profile");

		   Flist argFlist = flistCreate();
                   Poid cpPoid = poidCreate (dbID,"/config/credit_profile", -1);
                   flistSetPoid( argFlist, PIN_FLD_POID, cpPoid );
                   flistSetElem( search, PIN_FLD_ARGS, argFlist, 1 );

                   Flist result = flistCreate();
                   flistSetElem(search, PIN_FLD_RESULTS,result, 0);

                   pinlog(3, "Search Flist\n" + flistToStr( search ) );

                   // Do a readobject
                   Flist out = pcmOpCatch(7, 0, search, PINERR);
                   pinlog(3, "Result Flist\n\n" + flistToStr( out) );

                   Flist creditFlist = flistGetElem(out, PIN_FLD_RESULTS, 0);
                   flistSetEnum( OUT, PIN_FLD_RESULT, 1);

                   // Get the credit profile index from each balances 
		   // in the input flist
                   Iterator j = flistGetElements( IN, PIN_FLD_BALANCES );
                   while( iteratorHasMore( j ) ) {
                       Flist h = iteratorGetNext( j );
                       Long recid = iteratorGetRecId( j );
                       if( flistFldExists( h, PIN_FLD_CREDIT_PROFILE )) {
                           Long index = flistGetLong( h, PIN_FLD_CREDIT_PROFILE );
                           Flist tmpFlist = flistGetElem
			       (creditFlist,PIN_FLD_PROFILES, index);
                           Decimal creditLimit = flistGetDecimal
			       (tmpFlist, PIN_FLD_CREDIT_LIMIT);
                           pinlog(3, " Credit Profile Index :" + longToStr(index) +
                                 " Credit Limit :" + decimalToStr(creditLimit) );
                           if ( creditLimit > CREDIT_LIMIT_ALLOWED ) {
                                   flistSetEnum( OUT, PIN_FLD_RESULT, 0);
                           }
                        }
                        else {
                            pinlog(2,  "PIN_FLD_CREDIT_PROFILE not found");
                                flistSetEnum( OUT, PIN_FLD_RESULT, 0);
                        }
                   }

				pinlog(3, "Input Flist\n" + flistToStr( IN ) );
                                // Get the config business_profile poid
                                if( flistFldExists( IN, PIN_FLD_BUSINESS_PROFILE_OBJ)) {
                                        pinlog(2,  " Business_profile Validation for ACTG_TYPE");

                                        Long default_accounting_type_set = 0; // none

                                        Poid biPoid = flistGetPoid(IN, PIN_FLD_POID);
                                        Poid bpPoid = flistGetPoid(IN, PIN_FLD_BUSINESS_PROFILE_OBJ);

                                        // Call GET_BUSINESS_PROFILE_INFO to get the key value pair
                                        Flist readFlist = flistCreate();
                                        flistSetPoid(readFlist, PIN_FLD_POID, bpPoid);
                                        Flist proFlist  = flistCreate();
                                        flistSetStr(proFlist, PIN_FLD_PAIR_KEY, "Default_Accounting_Type");
                                        flistSetStr(proFlist, PIN_FLD_OBJ_TYPE, "");
                                        flistSetElem(readFlist, PIN_FLD_PROFILES, proFlist, 0);
                                        Flist out = pcmOpCatch(3909, 0, readFlist, PINERR);
                                        pinlog(3, "Iscript call Get_business_profile_info return Flist\n\n" + flistToStr( out) );

                                        Iterator p = flistGetElements( out, PIN_FLD_PROFILES );
                                        while ( iteratorHasMore(p) ) {
                                                Flist profilesFlist = iteratorGetNext(p);
                                                String accounting_type = flistGetStr(profilesFlist, PIN_FLD_PAIR_VALUE);

                                                if ((accounting_type == "Open_Item") OR
                                                        (accounting_type == "Balance_Forward") OR (accounting_type == "none")) {
							flistSetEnum(OUT, PIN_FLD_RESULT, 1);
                                                        if (accounting_type == "none") {
                                                                pinlog(2,  "None set for ACTG_TYPE");
                                                        } else {
                                                                // Billinfo Creation Time set it to default.
                                                                if ( poidIsTypeOnly( biPoid ) ) {
                                                                        if (accounting_type == "Open_Item"){
                                                                                flistSetEnum( OUT, PIN_FLD_ACTG_TYPE, 1);
										pinlog(2,  "Open_Item set for ACTG_TYPE");
                                                                        }
                                                                        if (accounting_type == "Balance_Forward") {
                                                                                flistSetEnum( OUT, PIN_FLD_ACTG_TYPE, 2);
										pinlog(2,  "Balance_Forward set for ACTG_TYPE");
                                                                        }
                                                                } else {
                                                                        // If ACTG_TYPE provided in the input because of
                                                                        // CHANGE_BUSINESS_PROFILE and MODIFY_BILLINFO
                                                                        if (flistFldExists( IN, PIN_FLD_ACTG_TYPE)) {
                                                                           Long newActgType = flistGetEnum(IN,PIN_FLD_ACTG_TYPE);
                                                                           if (accounting_type == "Open_Item") {
                                                                                default_accounting_type_set = 1;
                                                                           }
                                                                           if (accounting_type == "Balance_Forward") {
                                                                                default_accounting_type_set = 2;
                                                                           }
                                                                           if (newActgType != default_accounting_type_set) {
                                                                               pinlog(2,  "PIN_FLD_ACTG_TYPE  cannot be changed");
                                                                                flistSetEnum( OUT, PIN_FLD_RESULT, 0);
                                                                           }
                                                                        }
                                                                }
                                                        }
                                                } else {
                                                        pinlog(2,  "Error undefined Default_Accounting_type: "
                                                                "Defined Values are Open_Item or Balance_Forward or none");
                                                        flistSetEnum( OUT, PIN_FLD_RESULT, 0);
                                                }
                                        } // while
                                }

                                pinlog(3, "Input Flist\n" + flistToStr( IN ) );
                                if( flistFldExists( IN, PIN_FLD_BUSINESS_PROFILE_OBJ)) {
                                        pinlog(2,  " Business_profile Validations for Sharing_Groups");
                                        Bool found = false;

                                        Poid biPoid = flistGetPoid(IN, PIN_FLD_POID);
                                        Poid bpPoid = flistGetPoid(IN, PIN_FLD_BUSINESS_PROFILE_OBJ);

                                        flistSetEnum( OUT, PIN_FLD_RESULT, 1);

                                        // Call GET_BUSINESS_PROFILE_INFO to get the key value pair
                                        Flist readFlist = flistCreate();
                                        flistSetPoid(readFlist, PIN_FLD_POID, bpPoid);
                                        Flist proFlist  = flistCreate();
                                        flistSetStr(proFlist, PIN_FLD_PAIR_KEY, "Sharing_Groups_Enabled");
                                        flistSetStr(proFlist, PIN_FLD_OBJ_TYPE, "/config/business_profile");
                                        flistSetStr(proFlist, PIN_FLD_OBJ_TYPE, "");
                                        flistSetElem(readFlist, PIN_FLD_PROFILES, proFlist, 0);
                                        Flist out = pcmOpCatch(3909, 0, readFlist, PINERR);

                                        // Check if Sharing_Group_Enabled is set.
                                        Iterator j = flistGetElements(out, PIN_FLD_PROFILES );
                                        while( iteratorHasMore( j ) )  {
                                           //break; doesn't work in for loop
                                           Long recid = iteratorGetRecId( j );
                                           Flist profFlist = iteratorGetNext( j );
                                            if (found == false) {
                                                String key_pair = flistGetStr(profFlist, PIN_FLD_PAIR_KEY);
                                                if (key_pair == "Sharing_Groups_Enabled")
                                                {
							pinlog(3, "Business_profiles PROFILES\n\n" + flistToStr( profFlist) );
                                                        String key_value = flistGetStr(profFlist, PIN_FLD_PAIR_VALUE);
							if ((key_value == "no") or (key_value == "yes")) {
								if (key_value == "no") {
								   pinlog(2,  "KeyValue set to no for Sharing_Groups");
								   flistSetEnum( OUT, PIN_FLD_RESULT, 0);
								 } else if (key_value == "yes") {
								   pinlog(2,  "KeyValue set to yes for Sharing_Groups");
								   flistSetEnum( OUT, PIN_FLD_RESULT, 1);
								 }
								found = true;
							} else {
								pinlog(2,  "Error undefined Sharing_Groups_Enabled value: "
									"Defined Values are yes or no - case sensitive");
								flistSetEnum( OUT, PIN_FLD_RESULT, 0);
							}
                                                }
                                            } // found is false
                                        } //while
                                } // IF BUSINESS_PROFILE_OBJ exists
